  {
   "cell_type": "markdown",
   "metadata": {},
   "source": [
    "### Определение комбинаций признаков для тестирования"
   ]
  },
  {
   "cell_type": "code",
   "execution_count": 20,
   "metadata": {},
   "outputs": [
    {
     "name": "stdout",
     "output_type": "stream",
     "text": [
      "Предлагаемые комбинации признаков:\n",
      "\n",
      "Все признаки (5 признаков): ['avg_income', 'income_inequality', 'GDP', 'income_ratio', 'region_encoded']\n",
      "Без мультиколлинеарности (0 признаков): []\n",
      "Важные по RF (топ-3) (3 признаков): ['avg_income', 'GDP', 'income_ratio']\n",
      "Высокая корреляция + низкий VIF (0 признаков): []\n",
      "Экономические + регион (4 признаков): ['avg_income', 'income_inequality', 'GDP', 'region_encoded']\n"
     ]
    }
   ],
   "source": [
    "# На основе анализа предлагаем несколько комбинаций\n",
    "\n",
    "# Комбинация 1: Все признаки (базовая)\n",
    "features_combo1 = list(X.columns)\n",
    "\n",
    "# Комбинация 2: Убираем признаки с высокой мультиколлинеарностью (VIF > 5)\n",
    "high_vif_features = vif_data[vif_data['VIF'] > 5]['feature'].tolist()\n",
    "features_combo2 = [col for col in X.columns if col not in high_vif_features]\n",
    "\n",
    "# Комбинация 3: Самые важные по Random Forest (топ-3)\n",
    "features_combo3 = feature_importance.head(3)['feature'].tolist()\n",
    "\n",
    "# Комбинация 4: Признаки с высокой корреляцией с target и низкой мультиколлинеарностью\n",
    "features_combo4 = []\n",
    "for feature in X.columns:\n",
    "    corr_with_target = abs(corr_matrix.loc[feature, 'happyScore'])\n",
    "    vif_value = vif_data[vif_data['feature'] == feature]['VIF'].values[0]\n",
    "    if corr_with_target > 0.3 and vif_value < 5:\n",
    "        features_combo4.append(feature)\n",
    "\n",
    "# Комбинация 5: Только экономические показатели\n",
    "economic_features = ['avg_income', 'median_income', 'income_inequality', 'GDP']\n",
    "features_combo5 = [feat for feat in economic_features if feat in X.columns]\n",
    "features_combo5.append('region_encoded')\n",
    "\n",
    "print(\"Предлагаемые комбинации признаков:\\n\")\n",
    "combinations = {\n",
    "    'Все признаки': features_combo1,\n",
    "    'Без мультиколлинеарности': features_combo2,\n",
    "    'Важные по RF (топ-3)': features_combo3,\n",
    "    'Высокая корреляция + низкий VIF': features_combo4,\n",
    "    'Экономические + регион': features_combo5\n",
    "}\n",
    "\n",
    "for name, features in combinations.items():\n",
    "    print(f\"{name} ({len(features)} признаков): {features}\")"
   ]
  },
  {
   "cell_type": "markdown",
   "metadata": {},
   "source": [
    "### Функция для оценки моделей"
   ]
  },
  {
   "cell_type": "code",
   "execution_count": 21,
   "metadata": {},
   "outputs": [],
   "source": [
    "def evaluate_feature_combination(X, y, features, model_name='LinearRegression', test_size=0.2, random_state=42):\n",
    "    \"\"\"\n",
    "    Оценивает комбинацию признаков с помощью указанной модели\n",
    "    \"\"\"\n",
    "    # Выбираем указанные признаки\n",
    "    X_selected = X[features]\n",
    "    \n",
    "    # Разделяем данные\n",
    "    X_train, X_test, y_train, y_test = train_test_split(\n",
    "        X_selected, y, test_size=test_size, random_state=random_state\n",
    "    )\n",
    "    \n",
    "    # Масштабирование признаков\n",
    "    scaler = StandardScaler()\n",
    "    X_train_scaled = scaler.fit_transform(X_train)\n",
    "    X_test_scaled = scaler.transform(X_test)\n",
    "    \n",
    "    # Выбор модели\n",
    "    if model_name == 'LinearRegression':\n",
    "        model = LinearRegression()\n",
    "    elif model_name == 'Ridge':\n",
    "        model = Ridge(alpha=1.0)\n",
    "    elif model_name == 'Lasso':\n",
    "        model = Lasso(alpha=0.01)\n",
    "    elif model_name == 'RandomForest':\n",
    "        model = RandomForestRegressor(n_estimators=100, random_state=random_state)\n",
    "    else:\n",
    "        model = LinearRegression()\n",
    "    \n",
    "    # Обучение и предсказание\n",
    "    model.fit(X_train_scaled, y_train)\n",
    "    y_pred = model.predict(X_test_scaled)\n",
    "    \n",
    "    # Метрики\n",
    "    metrics = {\n",
    "        'R²': r2_score(y_test, y_pred),\n",
    "        'RMSE': np.sqrt(mean_squared_error(y_test, y_pred)),\n",
    "        'MAE': mean_absolute_error(y_test, y_pred),\n",
    "        'n_features': len(features),\n",
    "        'features': features\n",
    "    }\n",
    "    \n",
    "    # Кросс-валидация\n",
    "    cv_scores = cross_val_score(model, X_train_scaled, y_train, cv=5, scoring='r2')\n",
    "    metrics['CV R² mean'] = cv_scores.mean()\n",
    "    metrics['CV R² std'] = cv_scores.std()\n",
    "    \n",
    "    return metrics, model, (X_test_scaled, y_test, y_pred)"
   ]
  },
