    "# Сравниваем все комбинации с Linear Regression\n",
    "results = []\n",
    "\n",
    "for combo_name, features in combinations.items():\n",
    "    if len(features) > 0:  # Проверяем, что есть признаки\n",
    "        metrics, model, _ = evaluate_feature_combination(\n",
    "            X, y, features, model_name='LinearRegression'\n",
    "        )\n",
    "        metrics['combo_name'] = combo_name\n",
    "        results.append(metrics)\n",
    "\n",
    "# Создаем DataFrame с результатами\n",
    "results_df = pd.DataFrame(results)\n",
    "results_df = results_df.sort_values('R²', ascending=False)\n",
    "\n",
    "print(\"Сравнение комбинаций признаков (Linear Regression):\\n\")\n",
    "print(results_df[['combo_name', 'n_features', 'R²', 'CV R² mean', 'RMSE', 'MAE']])\n",
    "\n",
    "# Визуализация результатов\n",
    "fig, axes = plt.subplots(1, 2, figsize=(14, 5))\n",
    "\n",
    "# График R²\n",
    "axes[0].barh(results_df['combo_name'], results_df['R²'], color='skyblue')\n",
    "axes[0].set_xlabel('R² Score')\n",
    "axes[0].set_title('Качество моделей (R²) по комбинациям признаков')\n",
    "axes[0].axvline(x=results_df['R²'].max(), color='red', linestyle='--', alpha=0.5)\n",
    "\n",
    "# График RMSE\n",
